import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"41. Travelling Allowance","description":"","frontmatter":{"title":"41. Travelling Allowance","eba":"Health Allied & Managers Admin 2021-2025","topics":["allowances","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/allowances/41-travelling-allowance.md","filePath":"ebas/has-managers-admin/common-terms/allowances/41-travelling-allowance.md"}'),n={name:"ebas/has-managers-admin/common-terms/allowances/41-travelling-allowance.md"};function s(l,e,i,m,p,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_41-travelling-allowance" tabindex="-1">41. Travelling Allowance <a class="header-anchor" href="#_41-travelling-allowance" aria-label="Permalink to &quot;41. Travelling Allowance&quot;">​</a></h1><p><strong>41.1</strong> Employees other than Dental Assistants employed by DHSV</p><p><strong>(a)</strong> This subclause 41.1 does not apply to Dental Assistants employed by DHSV.</p><p><strong>(b)</strong> When an Employee is travelling whilst on duty, if the Employer cannot provide the appropriate transport, all reasonably incurred expenses in respect of fares, meals and accommodation will be met by the Employer on production of receipted accounts, or other evidence acceptable to the Employer.</p><p><strong>(c)</strong> An Employee will not be entitled to reimbursement for work-related travelling expenses that exceed the mode of transport, meals or the standard of accommodation agreed for the purpose with the Employer.</p><p><strong>(d)</strong> Where an Employer requires an Employee to use their own motor vehicle in the performance of their duties, such Employee will be paid</p><p>the per kilometre vehicle allowances pursuant to Part 1 of Schedule 2C or Part 1 or 2 of <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a> (as applicable).</p><p><strong>41.2</strong> Dental Assistants employed by DHSV This subclause 41.2 only applies to Dental Assistants employed by DHSV.</p><p><strong>(a)</strong> Use of Own Vehicle</p><p><strong>(i)</strong> In accordance with the Employer’s Reimbursement of Expenses policy, as varied from time to time, where an Employee is required to work at a location that involves travel using their own motor vehicle, and such travel is in excess of their nominated daily threshold, they will be entitled to claim travel expenses for the distance travelled in excess of the threshold.</p><p><strong>(ii)</strong> The daily threshold for all Employees is 40 kilometres, with the exception of those Employees who reside more than 20 kilometres from their designated base work location. In these circumstances, the threshold is the distance from home to that base work location and return.</p><p><strong>(iii)</strong> In addition to subclauses 41.2(a)(i) and 41.2(a)(ii) above, where an Employee is required to travel from one work location to another throughout the day, using their own motor vehicle, the distance is fully claimable.</p><p><strong>(iv)</strong> The vehicle allowances payable per kilometre for work- related travel over the life of the agreement are set out in</p><p><strong>(b)</strong> Travel to Distant Location</p><p><strong>(i)</strong> Employees will be compensated for excess travel to a distant location for work purposes (including for white chair examinations, special deliveries and collection of stores) in accordance with the Employer’s Reimbursement of Expenses policy, as varied from time to time.</p><p><strong>(ii)</strong> Where an Employee is required to travel to a location that is distant from their nominated place of work, and such travel involves more than 30 minutes in excess of their normal travel from home to a nominated place of duty, and more than 30 minutes travel in excess of their normal travel from their nominated place of duty home, the Employee will be compensated for the excess travel time by: <strong>(A)</strong> payment of overtime; or <strong>(B)</strong> time off in lieu of overtime payment.</p><p>Plain language terms: travel expenses, travel reimbursement, mileage.</p>',17)])])}const g=t(n,[["render",s]]);export{d as __pageData,g as default};
